const intents = $('Find Organization and intents').first()?.json?.intents || [];
const doable = intents.filter((i) => i.action === "get" || i.action === "create").slice(0, 3);
const intentLines = doable.map((i) => `- id: "${i.name}" | description: "${i.description}"`).join("
");
const prompt = `You are a message classifier.
Determine if the message is a GREETING (hi/hello/hey/etc).
If greeting: isWelcome=true, write welcome with user name "${userName}" and org "${orgName}", generate button titles (max 20 chars) per intent.
If not: isWelcome=false, empty welcomeMessage and buttons.

INTENTS:
${intentLines}

USER MESSAGE: "${userMessage}"

JSON only:
{"isWelcome": bool, "welcomeMessage": "string", "buttons": [{"id": "intent_name", "title": "max 20"}]}`;
